// Type Definitions
const typeDefs = gql`
  enum InvoiceStatus {
    DRAFT
    PENDING
    PAID
    OVERDUE
    CANCELLED
  }

  type InvoiceItem {
    description: String!
    quantity: Int!
    unitPrice: Float!
    amount: Float!
  }

  type Invoice {
    id: ID!
    invoiceNumber: String!
    clientName: String!
    clientEmail: String!
    items: [InvoiceItem!]!
    subtotal: Float!
    taxRate: Float!
    taxAmount: Float!
    totalAmount: Float!
    currency: String!
    status: InvoiceStatus!
    issuedDate: String!
    dueDate: String!
    paidDate: String
    notes: String
    createdBy: String!
  }

  type Query {
    invoice(id: ID!): Invoice
    invoices(status: InvoiceStatus, limit: Int, offset: Int): InvoiceListResult!
  }

  type InvoiceListResult {
    invoices: [Invoice!]!
    totalCount: Int!
  }

  input InvoiceItemInput {
    description: String!
    quantity: Int!
    unitPrice: Float!
  }

  input CreateInvoiceInput {
    clientName: String!
    clientEmail: String!
    items: [InvoiceItemInput!]!
    taxRate: Float!
    currency: String
    dueDate: String!
    notes: String
  }

  input UpdateInvoiceStatusInput {
    id: ID!
    status: InvoiceStatus!
  }

  type Mutation {
    createInvoice(input: CreateInvoiceInput!): Invoice!
    updateInvoiceStatus(input: UpdateInvoiceStatusInput!): Invoice!
    deleteInvoice(id: ID!): Boolean!
  }
`;

// Resolvers
const resolvers = {
  Query: {
    invoice: (parent, { id }, context) => {
      // context.user is available from authentication middleware
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoice = invoicesDB.find((inv) => inv.id === id);

      if (!invoice) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      // Users can query any invoice they have the ID for (as per requirements)
      return invoice;
    },

    invoices: (parent, { status, limit = 10, offset = 0 }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required.');
      }

      let filteredInvoices = [...invoicesDB];

      // Filter by status if provided
      if (status) {
        filteredInvoices = filteredInvoices.filter((inv) => inv.status === status);
      }

      const totalCount = filteredInvoices.length;
      const paginatedInvoices = filteredInvoices.slice(offset, offset + limit);

      return {
        invoices: paginatedInvoices,
        totalCount
      };
    }
  },

  Mutation: {
    createInvoice: (parent, { input }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const { clientName, clientEmail, items, taxRate, currency = 'USD', dueDate, notes } = input;

      // Validate items
      if (!items || items.length === 0) {
        throw new Error('Invoice must have at least one item.');
      }

      // Calculate amounts for each item and totals
      const calculatedItems = items.map((item) => ({
        description: item.description,
        quantity: item.quantity,
        unitPrice: item.unitPrice,
        amount: parseFloat((item.quantity * item.unitPrice).toFixed(2))
      }));

      const subtotal = parseFloat(
        calculatedItems.reduce((sum, item) => sum + item.amount, 0).toFixed(2)
      );
      const taxAmount = parseFloat((subtotal * taxRate).toFixed(2));
      const totalAmount = parseFloat((subtotal + taxAmount).toFixed(2));

      // Generate new invoice
      const newId = String(invoicesDB.length + 1);
      const invoiceNumber = `INV-2024-${String(invoicesDB.length + 1).padStart(3, '0')}`;

      const newInvoice = {
        id: newId,
        invoiceNumber,
        clientName,
        clientEmail,
        items: calculatedItems,
        subtotal,
        taxRate,
        taxAmount,
        totalAmount,
        currency,
        status: 'PENDING',
        issuedDate: new Date().toISOString().split('T')[0],
        dueDate,
        paidDate: null,
        notes: notes || null,
        createdBy: user.id
      };

      invoicesDB.push(newInvoice);

      return newInvoice;
    },

    updateInvoiceStatus: (parent, { input }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const { id, status } = input;

      const invoiceIndex = invoicesDB.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      const invoice = invoicesDB[invoiceIndex];

      // Validate status transitions
      const validTransitions = {
        DRAFT: ['PENDING', 'CANCELLED'],
        PENDING: ['PAID', 'OVERDUE', 'CANCELLED'],
        OVERDUE: ['PAID', 'CANCELLED'],
        PAID: [],
        CANCELLED: []
      };

      const allowedStatuses = validTransitions[invoice.status];
      if (!allowedStatuses || !allowedStatuses.includes(status)) {
        throw new Error(
          `Cannot transition invoice from "${invoice.status}" to "${status}". Allowed transitions: ${allowedStatuses.join(', ') || 'none'}.`
        );
      }

      // Update the invoice status
      invoicesDB[invoiceIndex] = {
        ...invoice,
        status,
        paidDate: status === 'PAID' ? new Date().toISOString().split('T')[0] : invoice.paidDate
      };

      return invoicesDB[invoiceIndex];
    },

    deleteInvoice: (parent, { id }, context) => {
      const user = context.user;

      if (!user) {
        throw new Error('Authentication required.');
      }

      const invoiceIndex = invoicesDB.findIndex((inv) => inv.id === id);

      if (invoiceIndex === -1) {
        throw new Error(`Invoice with ID "${id}" not found.`);
      }

      const invoice = invoicesDB[invoiceIndex];

      // Only allow deletion of DRAFT or CANCELLED invoices
      if (!['DRAFT', 'CANCELLED'].includes(invoice.status)) {
        throw new Error(
          `Cannot delete invoice with status "${invoice.status}". Only DRAFT or CANCELLED invoices can be deleted.`
        );
      }

      invoicesDB.splice(invoiceIndex, 1);

      return true;
    }
  }
};

// Simulated authentication middleware (already verified user)
const authMiddleware = (req, res, next) => {
  // In a real app, the JWT/session would have already been verified
  // We simulate an authenticated user being attached to the request
  req.user = {
    id: 'user-1',
    email: 'john@example.com',
    name: 'John Doe',
    role: 'admin'
  };
  next();
};

async function startServer() {
  const app = express();

  // Apply auth middleware before Apollo
  app.use(authMiddleware);

  const server = new ApolloServer({
    typeDefs,
    resolvers,
    context: ({ req }) => {
      // Pass the authenticated user from middleware into GraphQL context
      return {
        user: req.user
      };
    },
    formatError: (error) => {
      console.error('GraphQL Error:', error.message);
      return {
        message: error.message,
        path: error.path,
        extensions: {
          code: error.extensions?.code || 'INTERNAL_SERVER_ERROR'
        }
      };
    }
  });

  await server.start();

  server.applyMiddleware({ app, path: '/graphql' });

  const PORT = process.env.PORT || 4000;

  app.listen(PORT, () => {
    console.log(`Invoice Management GraphQL API running at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`\nExample queries:`);
    console.log(`  - Get invoice by ID: { invoice(id: "1") { id invoiceNumber clientName totalAmount status items { description amount } } }`);
    console.log(`  - List all invoices: { invoices { invoices { id invoiceNumber clientName totalAmount status } totalCount } }`);
    console.log(`  - Filter by status: { invoices(status: PAID) { invoices { id invoiceNumber totalAmount } totalCount } }`);
  });
}

startServer().catch((err) => {
  console.error('Failed to start server:', err);
});